INSERT INTO "public"."Artworks" ("id", "created_at", "artwork_name", "author_name", "description", "description_cs") VALUES ('1', '2026-03-13 10:17:42.115701+00', 'Landscape with an Obelisk', 'Govert Flinck', 'Dutch landscape painting from 1638 that was stolen from the Isabella Stewart Gardner Museum in Boston in 1990 and remains missing.', 'Krajinný obraz ze 17. století od nizozemského malíře Govert Flincka. Byl ukraden z Gardnerova muzea v Bostonu v roce 1990.'), ('2', '2026-03-13 10:17:42.115701+00', 'Man with a Pipe', 'Jean Metzinger', 'Cubist painting that disappeared in 1998 while being transported on loan from Lawrence University in Wisconsin.', 'Kubistický obraz francouzského malíře Jeana Metzingera. Zmizel během přepravy na výstavu v roce 1998.'), ('3', '2026-03-13 10:17:42.115701+00', 'Le chemin de Sèvres', 'Jean-Baptiste-Camille Corot', 'Landscape painting stolen by a visitor during open hours from the Louvre in Paris.', null), ('4', '2026-03-13 10:17:42.115701+00', 'View of Auvers-sur-Oise', 'Paul Cézanne', 'Landscape painting stolen from the Ashmolean Museum in Oxford on the night of 31 December 1999 during New Year celebrations.', 'Krajina od Paula Cézanna zobrazující město Auvers-sur-Oise. Obraz byl ukraden z Ashmolean Museum v Oxfordu v roce 1999.'), ('5', '2026-03-13 10:17:42.115701+00', 'A Cavalier', 'Frans van Mieris the Elder', 'Small Dutch Golden Age portrait stolen from the Art Gallery of New South Wales in Sydney by a visitor during opening hours.', 'Malý portrét jezdce od nizozemského malíře Franse van Mierise. Byl ukraden z galerie v Sydney.'), ('6', '2026-03-13 10:17:42.115701+00', 'Venus with a Mirror', 'Jacopo Palma il Giovane', 'Baroque painting stolen in 2010 from Hübner Palace in Budapest during a robbery.', 'Barokní obraz Jacopa Palmy mladšího zobrazující bohyni Venuši se zrcadlem. Byl ukraden při loupeži v Budapešti v roce 2010.'), ('7', '2026-03-13 10:17:42.115701+00', 'The Concert', 'Johannes Vermeer', 'Dutch Golden Age painting de